 1→import { createSignal } from 'solid-js';
 2→
 3→// Bar animation state
 4→export function createAnimatedBars() {
 5→  const [healthPct, setHealthPct] = createSignal(75);
 6→  const [manaPct, setManaPct] = createSignal(60);
 7→  const [xpPct, setXpPct] = createSignal(40);
 8→  const [buildPct, setBuildPct] = createSignal(55);
 9→
10→  function animateBars() {
11→    setHealthPct(Math.floor(Math.random() * 60 + 20));
12→    setManaPct(Math.floor(Math.random() * 60 + 20));
13→    setXpPct(Math.floor(Math.random() * 60 + 20));
14→    setBuildPct(Math.floor(Math.random() * 60 + 20));
15→  }
16→
17→  return {
18→    healthPct, manaPct, xpPct, buildPct,
19→    setHealthPct, setManaPct, setXpPct, setBuildPct,
20→    animateBars,
21→  };
22→}
23→
24→// Loading bar state
25→export function createLoadingBar() {
26→  const [progress, setProgress] = createSignal(0);
27→  let interval: ReturnType<typeof setInterval> | null = null;
28→
29→  function start() {
30→    setProgress(0);
31→    if (interval) clearInterval(interval);
32→    interval = setInterval(() => {
33→      setProgress(prev => {
34→        const next = prev + Math.random() * 8 + 2;
35→        if (next >= 100) {
36→          clearInterval(interval!);
37→          interval = null;
38→          setTimeout(() => {
39→            setProgress(0);
40→            setTimeout(() => start(), 100);
41→          }, 1500);
42→          return 100;
43→        }
44→        return next;
45→      });
46→    }, 400);
47→  }
48→
49→  function stop() {
50→    if (interval) {
51→      clearInterval(interval);
52→      interval = null;
53→    }
54→  }
55→
56→  return { progress, start, stop };
57→}
58→

 1→import { createSignal } from 'solid-js';
 2→
 3→const [goldTarget, setGoldTarget] = createSignal(500);
 4→const [goldCurrent, setGoldCurrent] = createSignal(500);
 5→const [lumberTarget, setLumberTarget] = createSignal(300);
 6→const [lumberCurrent, setLumberCurrent] = createSignal(300);
 7→
 8→function stepCounter(current: number, target: number): number {
 9→  if (current === target) return current;
10→  const diff = target - current;
11→  const next = current + Math.sign(diff) * Math.max(1, Math.floor(Math.abs(diff) * 0.2));
12→  return Math.abs(target - next) < 2 ? target : next;
13→}
14→
15→export function tickResources() {
16→  setGoldTarget(prev => Math.max(0, Math.min(9999, prev + Math.floor(Math.random() * 20) - 5)));
17→  setLumberTarget(prev => Math.max(0, Math.min(9999, prev + Math.floor(Math.random() * 15) - 4)));
18→}
19→
20→export function animateCounters() {
21→  setGoldCurrent(prev => stepCounter(prev, goldTarget()));
22→  setLumberCurrent(prev => stepCounter(prev, lumberTarget()));
23→}
24→
25→export { goldCurrent, lumberCurrent, goldTarget, lumberTarget, setGoldTarget, setLumberTarget };
26→
27→// Cheat codes
28→let cheatBuffer = '';
29→const CHEATS: Record<string, () => void> = {
30→  greedisgood: () => {
31→    setGoldTarget(prev => Math.min(9999, prev + 500));
32→    setLumberTarget(prev => Math.min(9999, prev + 500));
33→  },
34→  keysersoze: () => { setGoldTarget(prev => Math.min(9999, prev + 500)); },
35→  leafittome: () => { setLumberTarget(prev => Math.min(9999, prev + 500)); },
36→};
37→
38→export function handleCheatKey(key: string) {
39→  if (key.length === 1 && /[a-z]/i.test(key)) {
40→    cheatBuffer += key.toLowerCase();
41→    if (cheatBuffer.length > 20) cheatBuffer = cheatBuffer.slice(-20);
42→    for (const [code, fn] of Object.entries(CHEATS)) {
43→      if (cheatBuffer.endsWith(code)) {
44→        fn();
45→        cheatBuffer = '';
46→        break;
47→      }
48→    }
49→  }
50→}
51→

