 65→async function loadModel(path: string): Promise<ModelType> {
 66→  const cached = modelCache.get(path);
 67→  if (cached) return cached;
 68→
 69→  const res = await fetch(path);
 70→  if (!res.ok) throw new Error(`Failed to load worker unit model: ${path}`);
 71→  const ab = await res.arrayBuffer();
 72→  const model = parseMDX(ab);
 73→  modelCache.set(path, model);
 74→  return model;
 75→}
