 77→async function loadBLPMips(path: string): Promise<ImageData[]> {
 78→  const cached = blpCache.get(path);
 79→  if (cached) return cached;
 80→
 81→  const res = await fetch(path);
 82→  if (!res.ok) throw new Error(`Failed to load worker unit texture: ${path}`);
 83→  const ab = await res.arrayBuffer();
 84→  const blp = decodeBLP(ab);
 85→
 86→  const mips: ImageData[] = [];
 87→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
 88→  for (let i = 0; i < maxLevels; i++) {
 89→    const w = blp.width >> i;
 90→    const h = blp.height >> i;
 91→    if (w <= 0 || h <= 0) break;
 92→    try {
 93→      const img = getBLPImageData(blp, i);
 94→      if (!img || !img.width || !img.height) break;
 95→      mips.push(new ImageData(img.data, img.width, img.height));
 96→      if (img.width === 1 && img.height === 1) break;
 97→    } catch {
 98→      break;
 99→    }
100→  }
101→
102→  if (mips.length === 0) {
103→    throw new Error(`No mip levels decoded for worker unit texture: ${path}`);
104→  }
105→
106→  blpCache.set(path, mips);
107→  return mips;
108→}
