 13→function computeVisibleBounds2D(model: ModelType): { minX: number; maxX: number; minY: number; maxY: number } | null {
 14→  let minX = Number.POSITIVE_INFINITY;
 15→  let maxX = Number.NEGATIVE_INFINITY;
 16→  let minY = Number.POSITIVE_INFINITY;
 17→  let maxY = Number.NEGATIVE_INFINITY;
 18→  let hasVisible = false;
 19→  for (const geoset of model.Geosets || []) {
 20→    if (!geoset.Faces || geoset.Faces.length === 0) continue;
 21→    const verts = geoset.Vertices;
 22→    for (let i = 0; i < verts.length; i += 3) {
 23→      const x = verts[i];
 24→      const y = verts[i + 1];
 25→      if (x < minX) minX = x;
 26→      if (x > maxX) maxX = x;
 27→      if (y < minY) minY = y;
 28→      if (y > maxY) maxY = y;
 29→      hasVisible = true;
 30→    }
 31→  }
 32→  if (!hasVisible) return null;
 33→  return { minX, maxX, minY, maxY };
 34→}
