  1→import { createEffect, onCleanup, onMount } from 'solid-js';
  2→import type { Race } from '../lib/types';
  3→import { RACE_PREFIXES } from '../state/race';
  4→
  5→interface Props {
  6→  race: Race;
  7→  leftOnly?: boolean;
  8→}
  9→
 10→type TileIndex = 1 | 2 | 3 | 4;
 11→
 12→const TILE_INDICES: readonly TileIndex[] = [1, 2, 3, 4];
 13→const TOP_SLICE_V0 = 0;
 14→const TOP_SLICE_V1 = 0.125;
 15→const TILE2_LEFT_U0 = 0;
 16→const TILE2_LEFT_U1 = 0.33984375;
 17→const TILE2_RIGHT_U0 = 0.79296875;
 18→const TILE2_RIGHT_U1 = 1;
 19→
 20→const LEFT_TILE1_WIDTH_VW = 32;
 21→const LEFT_TILE2_WIDTH_VW = 10.875;
 22→const RIGHT_TILE2_WIDTH_VW = 6.875;
 23→const RIGHT_TILE3_WIDTH_VW = 32;
 24→const RIGHT_TILE4_WIDTH_VW = 4;
 25→const SEAM_PX = 1;
 26→
 27→function topTilePath(race: Race, index: TileIndex): string {
 28→  const tile = RACE_PREFIXES[race].tile;
 29→  return `/console/${race}/${tile}UITile0${index}.png`;
 30→}
 31→
 32→function compileShader(gl: WebGLRenderingContext, type: number, src: string): WebGLShader | null {
 33→  const shader = gl.createShader(type);
 34→  if (!shader) return null;
 35→  gl.shaderSource(shader, src);
 36→  gl.compileShader(shader);
 37→  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
 38→    console.error('Top HUD shader compile failed:', gl.getShaderInfoLog(shader));
 39→    gl.deleteShader(shader);
 40→    return null;
 41→  }
 42→  return shader;
 43→}
 44→
 45→function createProgram(gl: WebGLRenderingContext): WebGLProgram | null {
 46→  const vertexSource = `
 47→    attribute vec2 a_position;
 48→    attribute vec2 a_uv;
 49→    varying vec2 v_uv;
 50→    void main() {
 51→      gl_Position = vec4(a_position, 0.0, 1.0);
 52→      v_uv = a_uv;
 53→    }
 54→  `;
 55→  const fragmentSource = `
 56→    precision mediump float;
 57→    varying vec2 v_uv;
 58→    uniform sampler2D u_texture;
 59→    void main() {
 60→      vec4 color = texture2D(u_texture, v_uv);
 61→      if (color.a < 0.5) {
 62→        discard;
 63→      }
 64→      gl_FragColor = color;
 65→    }
 66→  `;
 67→
 68→  const vertexShader = compileShader(gl, gl.VERTEX_SHADER, vertexSource);
 69→  const fragmentShader = compileShader(gl, gl.FRAGMENT_SHADER, fragmentSource);
 70→  if (!vertexShader || !fragmentShader) return null;
 71→
 72→  const program = gl.createProgram();
 73→  if (!program) return null;
 74→
 75→  gl.attachShader(program, vertexShader);
 76→  gl.attachShader(program, fragmentShader);
 77→  gl.linkProgram(program);
 78→
 79→  gl.deleteShader(vertexShader);
 80→  gl.deleteShader(fragmentShader);
 81→
 82→  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
 83→    console.error('Top HUD program link failed:', gl.getProgramInfoLog(program));
 84→    gl.deleteProgram(program);
 85→    return null;
 86→  }
 87→
 88→  return program;
 89→}
