 91→export default function TopHudWebGL(props: Props) {
 92→  let canvasRef!: HTMLCanvasElement;
 93→  let gl: WebGLRenderingContext | null = null;
 94→  let program: WebGLProgram | null = null;
 95→  let quadBuffer: WebGLBuffer | null = null;
 96→  let positionLoc = -1;
 97→  let uvLoc = -1;
 98→  let textureLoc: WebGLUniformLocation | null = null;
 99→
100→  let destroyed = false;
101→  let drawQueued = false;
102→  let drawRaf = 0;
103→  let resizeObserver: ResizeObserver | null = null;
104→
105→  const textureCache = new Map<string, WebGLTexture>();
106→  const textureLoadCache = new Map<string, Promise<WebGLTexture | null>>();
107→  let activeTextures: Record<TileIndex, WebGLTexture> | null = null;
108→
109→  const requestDraw = () => {
110→    if (drawQueued || destroyed) return;
111→    drawQueued = true;
112→    drawRaf = window.requestAnimationFrame(() => {
113→      drawQueued = false;
114→      draw();
115→    });
116→  };
117→
118→  const syncCanvasSize = () => {
119→    if (!gl) return;
120→    const dpr = window.devicePixelRatio || 1;
121→    const cssWidth = Math.max(1, canvasRef.clientWidth || 1);
122→    const cssHeight = Math.max(1, canvasRef.clientHeight || 1);
123→    const width = Math.round(cssWidth * dpr);
124→    const height = Math.round(cssHeight * dpr);
125→    if (canvasRef.width !== width || canvasRef.height !== height) {
126→      canvasRef.width = width;
127→      canvasRef.height = height;
128→    }
129→    gl.viewport(0, 0, width, height);
130→  };
131→
132→  const drawQuad = (
133→    texture: WebGLTexture,
134→    x: number,
135→    y: number,
136→    w: number,
137→    h: number,
138→    u0: number,
139→    v0: number,
140→    u1: number,
141→    v1: number
142→  ) => {
143→    if (!gl || !quadBuffer) return;
144→    const canvasW = canvasRef.width;
145→    const canvasH = canvasRef.height;
146→    if (canvasW <= 0 || canvasH <= 0 || w <= 0 || h <= 0) return;
147→
148→    const x0 = (x / canvasW) * 2 - 1;
149→    const y0 = 1 - (y / canvasH) * 2;
150→    const x1 = ((x + w) / canvasW) * 2 - 1;
151→    const y1 = 1 - ((y + h) / canvasH) * 2;
152→
153→    const vertices = new Float32Array([
154→      x0, y0, u0, v0,
155→      x1, y0, u1, v0,
156→      x0, y1, u0, v1,
157→      x1, y0, u1, v0,
158→      x1, y1, u1, v1,
159→      x0, y1, u0, v1,
160→    ]);
161→
162→    gl.bindTexture(gl.TEXTURE_2D, texture);
163→    gl.bindBuffer(gl.ARRAY_BUFFER, quadBuffer);
164→    gl.bufferData(gl.ARRAY_BUFFER, vertices, gl.STREAM_DRAW);
165→    gl.drawArrays(gl.TRIANGLES, 0, 6);
166→  };
167→
168→  const draw = () => {
169→    if (!gl || !program || !quadBuffer || !activeTextures) return;
170→    syncCanvasSize();
171→
172→    const canvasW = canvasRef.width;
173→    const canvasH = canvasRef.height;
174→    if (canvasW <= 0 || canvasH <= 0) return;
175→
176→    gl.clear(gl.COLOR_BUFFER_BIT);
177→
178→    gl.useProgram(program);
179→    gl.bindBuffer(gl.ARRAY_BUFFER, quadBuffer);
180→    gl.enableVertexAttribArray(positionLoc);
181→    gl.vertexAttribPointer(positionLoc, 2, gl.FLOAT, false, 16, 0);
182→    gl.enableVertexAttribArray(uvLoc);
183→    gl.vertexAttribPointer(uvLoc, 2, gl.FLOAT, false, 16, 8);
184→    gl.activeTexture(gl.TEXTURE0);
185→    gl.uniform1i(textureLoc, 0);
186→
187→    const dpr = window.devicePixelRatio || 1;
188→    const seamPx = SEAM_PX * dpr;
189→    const vw = canvasW / 100;
190→    const topHudH = canvasH;
191→
192→    if (props.leftOnly) {
193→      const leftSpanVw = LEFT_TILE1_WIDTH_VW + LEFT_TILE2_WIDTH_VW;
194→      const leftTile1W = (LEFT_TILE1_WIDTH_VW / leftSpanVw) * canvasW + seamPx;
195→      const leftTile2X = leftTile1W - seamPx;
196→      const leftTile2W = canvasW - leftTile2X;
197→
198→      drawQuad(activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
199→      drawQuad(
200→        activeTextures[2],
201→        leftTile2X,
202→        0,
203→        leftTile2W,
204→        topHudH,
205→        TILE2_LEFT_U0,
206→        TOP_SLICE_V0,
207→        TILE2_LEFT_U1,
208→        TOP_SLICE_V1
209→      );
210→      return;
211→    }
212→
213→    const leftTile1W = LEFT_TILE1_WIDTH_VW * vw + seamPx;
214→    const leftTile2W = LEFT_TILE2_WIDTH_VW * vw + seamPx;
215→    const leftTile2X = leftTile1W - seamPx;
216→
217→    drawQuad(activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
218→    drawQuad(
219→      activeTextures[2],
220→      leftTile2X,
221→      0,
222→      leftTile2W,
223→      topHudH,
224→      TILE2_LEFT_U0,
225→      TOP_SLICE_V0,
226→      TILE2_LEFT_U1,
227→      TOP_SLICE_V1
228→    );
229→
230→    const rightTile2W = RIGHT_TILE2_WIDTH_VW * vw + seamPx;
231→    const rightTile3W = RIGHT_TILE3_WIDTH_VW * vw + seamPx;
232→    const rightTile4W = RIGHT_TILE4_WIDTH_VW * vw + seamPx;
233→    const rightTile4X = canvasW - rightTile4W;
234→    const rightTile3X = rightTile4X - (rightTile3W - seamPx);
235→    const rightTile2X = rightTile3X - (rightTile2W - seamPx);
236→
237→    drawQuad(
238→      activeTextures[2],
239→      rightTile2X,
240→      0,
241→      rightTile2W,
242→      topHudH,
243→      TILE2_RIGHT_U0,
244→      TOP_SLICE_V0,
245→      TILE2_RIGHT_U1,
246→      TOP_SLICE_V1
247→    );
248→    drawQuad(activeTextures[3], rightTile3X, 0, rightTile3W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
249→    drawQuad(activeTextures[4], rightTile4X, 0, rightTile4W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
250→  };
251→
252→  const loadTexture = (path: string): Promise<WebGLTexture | null> => {
253→    if (!gl) return Promise.resolve(null);
254→    const cached = textureCache.get(path);
255→    if (cached) return Promise.resolve(cached);
256→    const inflight = textureLoadCache.get(path);
257→    if (inflight) return inflight;
258→
259→    const promise = new Promise<WebGLTexture | null>((resolve) => {
260→      const image = new Image();
261→      image.onload = () => {
262→        if (!gl || destroyed) {
263→          textureLoadCache.delete(path);
264→          resolve(null);
265→          return;
266→        }
267→        const texture = gl.createTexture();
268→        if (!texture) {
269→          textureLoadCache.delete(path);
270→          resolve(null);
271→          return;
272→        }
273→        gl.bindTexture(gl.TEXTURE_2D, texture);
274→        gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, image);
275→        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
276→        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
277→        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
278→        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
279→        textureCache.set(path, texture);
280→        textureLoadCache.delete(path);
281→        resolve(texture);
282→      };
283→      image.onerror = () => {
284→        console.error(`Failed to load top HUD texture: ${path}`);
285→        textureLoadCache.delete(path);
286→        resolve(null);
287→      };
288→      image.src = path;
289→    });
290→
291→    textureLoadCache.set(path, promise);
292→    return promise;
293→  };
294→
295→  const loadRaceTextures = async (race: Race) => {
296→    if (!gl || destroyed) return;
297→    const paths = TILE_INDICES.map((index) => topTilePath(race, index));
298→    const loaded = await Promise.all(paths.map((path) => loadTexture(path)));
299→    if (destroyed || loaded.some((tex) => tex === null)) return;
300→
301→    activeTextures = {
302→      1: loaded[0]!,
303→      2: loaded[1]!,
304→      3: loaded[2]!,
305→      4: loaded[3]!,
306→    };
307→    requestDraw();
308→  };
309→
310→  onMount(() => {
311→    gl = canvasRef.getContext('webgl', {
312→      alpha: true,
313→      premultipliedAlpha: false,
314→      antialias: false,
315→      depth: false,
316→      stencil: false,
317→    });
318→
319→    if (!gl) {
320→      console.error('WebGL is unavailable for top HUD rendering.');
321→      return;
322→    }
323→
324→    program = createProgram(gl);
325→    if (!program) return;
326→
327→    positionLoc = gl.getAttribLocation(program, 'a_position');
328→    uvLoc = gl.getAttribLocation(program, 'a_uv');
329→    textureLoc = gl.getUniformLocation(program, 'u_texture');
330→    quadBuffer = gl.createBuffer();
331→
332→    if (positionLoc < 0 || uvLoc < 0 || !textureLoc || !quadBuffer) {
333→      console.error('Failed to initialize top HUD WebGL buffers.');
334→      return;
335→    }
