152→interface UnitQueueSectionProps {
153→  backdropUrl?: string;
154→  iconUrl?: string;
155→}
156→
157→const UNIT_QUEUE_SIZE = { width: 241, height: 93 } as const;
158→const UNIT_QUEUE_ACTIVE_ICON_BOX = { x: 6, y: 5, width: 42, height: 42 } as const;
159→const UNIT_QUEUE_ICON_BOXES = [
160→  UNIT_QUEUE_ACTIVE_ICON_BOX,
161→  { x: 5, y: 57, width: 31, height: 30 },
162→  { x: 45, y: 58, width: 31, height: 30 },
163→  { x: 85, y: 58, width: 31, height: 30 },
164→  { x: 125, y: 58, width: 31, height: 30 },
165→] as const;
166→
167→async function loadImage(src: string): Promise<HTMLImageElement> {
168→  return new Promise((resolve, reject) => {
169→    const img = new Image();
170→    img.onload = () => resolve(img);
171→    img.onerror = () => reject(new Error(`Failed to load image: ${src}`));
172→    img.src = src;
173→  });
174→}
175→
176→function drawNearest(
177→  ctx: CanvasRenderingContext2D,
178→  image: HTMLImageElement,
179→  x: number,
180→  y: number,
181→  width: number,
182→  height: number,
183→) {
184→  ctx.save();
185→  ctx.imageSmoothingEnabled = false;
186→  ctx.drawImage(image, x, y, width, height);
187→  ctx.restore();
188→}
189→
190→function drawUnitQueuePreview(
191→  canvas: HTMLCanvasElement,
192→  backdropImage: HTMLImageElement,
193→  iconImage: HTMLImageElement | null,
194→) {
195→  const rect = canvas.getBoundingClientRect();
196→  const cssW = Math.max(1, rect.width);
197→  const cssH = Math.max(1, rect.height);
198→  const dpr = window.devicePixelRatio || 1;
199→  const pxW = Math.max(1, Math.round(cssW * dpr));
200→  const pxH = Math.max(1, Math.round(cssH * dpr));
201→  if (canvas.width !== pxW || canvas.height !== pxH) {
202→    canvas.width = pxW;
203→    canvas.height = pxH;
204→  }
205→
206→  const ctx = canvas.getContext('2d');
207→  if (!ctx) return;
208→
209→  const scaleX = cssW / UNIT_QUEUE_SIZE.width;
210→  const scaleY = cssH / UNIT_QUEUE_SIZE.height;
211→
212→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
213→  ctx.clearRect(0, 0, cssW, cssH);
214→  ctx.imageSmoothingEnabled = false;
215→  ctx.drawImage(backdropImage, 0, 0, cssW, cssH);
216→  if (!iconImage) return;
217→
218→  for (const box of UNIT_QUEUE_ICON_BOXES) {
219→    drawNearest(ctx, iconImage, box.x * scaleX, box.y * scaleY, box.width * scaleX, box.height * scaleY);
220→  }
221→}
222→
223→export function UnitQueueSection(props: UnitQueueSectionProps) {
224→  let canvasRef: HTMLCanvasElement | undefined;
225→
226→  createEffect(() => {
227→    const canvas = canvasRef;
228→    const backdropUrl = props.backdropUrl;
229→    const iconUrl = props.iconUrl;
230→    if (!canvas || !backdropUrl) return;
231→
232→    let cancelled = false;
233→    void Promise.all([
234→      loadImage(backdropUrl),
235→      iconUrl ? loadImage(iconUrl) : Promise.resolve(null),
236→    ])
237→      .then(([backdropImage, iconImage]) => {
238→        if (cancelled) return;
239→        drawUnitQueuePreview(canvas, backdropImage, iconImage);
240→      })
241→      .catch((error) => console.error(error));
242→
243→    onCleanup(() => {
244→      cancelled = true;
245→    });
246→  });
247→
248→  return (
249→    <section class="section-card">
250→      <h3>Unit Queue</h3>
251→      <p class="section-desc">
252→        A task queue with progress indicator and cancelable pending slots. Perfect for managing build pipelines, AI agent workflows, or anything that trains in 30 seconds.
253→      </p>
254→      <div class="unit-queue-preview">
255→        <div class="unit-queue-stage" aria-label="Build queue backdrop preview">
256→          {props.backdropUrl ? (
