203→  const atlasW = borderImg.width;
204→  const atlasH = borderImg.height;
205→  const cellW = atlasW / 8;
206→  const corner = Math.max(1, Math.floor(Math.min(cellW, cssH * 0.35, cssW / 2, cssH / 2)));
207→  const inset = Math.max(1, Math.round(corner * 0.25));
208→
209→  ctx.fillStyle = '#000';
210→  ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
211→
212→  const pattern = ctx.createPattern(bgImg, 'repeat');
213→  if (pattern) {
214→    ctx.fillStyle = pattern;
215→    ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
216→  }
217→
218→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
219→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
220→  };
221→
222→  drawCell(4, 0, 0, corner, corner);
223→  drawCell(5, cssW - corner, 0, corner, corner);
224→  drawCell(6, 0, cssH - corner, corner, corner);
225→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
226→
227→  const edgeH = cssH - corner * 2;
228→  if (edgeH > 0) {
229→    drawCell(0, 0, corner, corner, edgeH);
230→    drawCell(1, cssW - corner, corner, corner, edgeH);
231→  }
232→
233→  const edgeW = cssW - corner * 2;
234→  if (edgeW > 0) {
235→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
