import { For, createEffect, createSignal, onCleanup, onMount, type Accessor } from 'solid-js';
import { decodeBLP, getBLPImageData } from 'war3-model';
import type { Race } from '../../lib/types';
import { RACE_PREFIXES } from '../../state/race';

const previewRaces: Array<{ race: Race; label: string }> = [
  { race: 'Human', label: 'Human' },
  { race: 'Orc', label: 'Orc' },
  { race: 'NightElf', label: 'Night Elf' },
  { race: 'Undead', label: 'Undead' },
];

const escButtonPressedOffsetXPx = 2;
const escButtonPressedOffsetYPx = 2;
const escSliderTrackWidthPx = 220;
const escSliderThumbWidthPx = 28;

interface RacePreviewAssets {
  escBgUrl: string;
  escBgDownUrl: string;
  escBorderUrl: string;
  escBorderDownUrl: string;
  escHoverUrl: string;
  sliderKnobUrl: string;
}

const EMPTY_RACE_PREVIEW_ASSETS: RacePreviewAssets = {
  escBgUrl: '',
  escBgDownUrl: '',
  escBorderUrl: '',
  escBorderDownUrl: '',
  escHoverUrl: '',
  sliderKnobUrl: '',
};

const EMPTY_RACE_PREVIEW_ASSET_MAP: Record<Race, RacePreviewAssets> = {
  Human: EMPTY_RACE_PREVIEW_ASSETS,
  Orc: EMPTY_RACE_PREVIEW_ASSETS,
  NightElf: EMPTY_RACE_PREVIEW_ASSETS,
  Undead: EMPTY_RACE_PREVIEW_ASSETS,
};

const blpDataUrlCache = new Map<string, Promise<string>>();
const imageCache = new Map<string, Promise<HTMLImageElement>>();

function shouldForceOpaqueOnZeroAlpha(path: string): boolean {
  return /\/buttons\/esc\/[^/]+\/[^/]+-options-(?:menu|button)-background(?:-down|-disabled)?\.blp$/i.test(path);
}

async function loadBlpDataUrl(path: string): Promise<string> {
  const cached = blpDataUrlCache.get(path);
  if (cached) return cached;

  const promise = (async () => {
    const res = await fetch(path);
    if (!res.ok) throw new Error(`Failed to fetch ${path}`);
    const ab = await res.arrayBuffer();
    const blp = decodeBLP(ab);
    const img = getBLPImageData(blp, 0);
    const pixelData = new Uint8ClampedArray(img.data);

    if (shouldForceOpaqueOnZeroAlpha(path)) {
      let allAlphaZero = true;
      for (let i = 3; i < pixelData.length; i += 4) {
        if (pixelData[i] !== 0) {
          allAlphaZero = false;
          break;
        }
      }
      if (allAlphaZero) {
        for (let i = 3; i < pixelData.length; i += 4) {
          pixelData[i] = 255;
        }
      }
    }

    const canvas = document.createElement('canvas');
    canvas.width = img.width;
    canvas.height = img.height;
    const ctx = canvas.getContext('2d');
    if (!ctx) throw new Error(`Failed to decode ${path}`);
    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
    return canvas.toDataURL('image/png');
  })();

  blpDataUrlCache.set(path, promise);
  return promise;
}

async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
  const cached = imageCache.get(url);
  if (cached) return cached;
  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
    img.src = url;
  });
  imageCache.set(url, promise);
  return promise;
}

function getEscSliderKnobPath(race: Race): string {
  if (race === 'Orc') return '/buttons/slider/orc-slider-knob.blp';
  if (race === 'NightElf') return '/buttons/slider/nightelf-slider-knob.blp';
  if (race === 'Undead') return '/buttons/slider/undead-slider-knob.blp';
  return '/buttons/slider/slider-knob.blp';
}

interface EscButtonSkin {
  bg: string;
  bgDown: string;
  border: string;
  borderDown: string;
  hover: string;
}

function getEscButtonSkin(race: Race): EscButtonSkin {
  const humanBorder = '/buttons/esc/human/human-options-button-border-up.blp';
  const humanBorderDown = '/buttons/esc/human/human-options-button-border-down.blp';

  if (race === 'Human') {
    return {
      bg: '/buttons/esc/human/human-options-menu-background.blp',
      bgDown: '/buttons/esc/human/human-options-menu-background.blp',
      border: humanBorder,
      borderDown: humanBorderDown,
      hover: '/buttons/esc/human/human-options-button-highlight.blp',
    };
  }

  if (race === 'Orc') {
    return {
      bg: '/buttons/esc/orc/orc-options-button-background.blp',
      bgDown: '/buttons/esc/orc/orc-options-button-background-down.blp',
      border: humanBorder,
      borderDown: humanBorderDown,
      hover: '/buttons/esc/orc/orc-options-button-highlight.blp',
    };
  }

  if (race === 'NightElf') {
    return {
      bg: '/buttons/esc/nightelf/nightelf-options-button-background.blp',
      bgDown: '/buttons/esc/nightelf/nightelf-options-button-background-down.blp',
      border: humanBorder,
      borderDown: humanBorderDown,
      hover: '/buttons/esc/nightelf/nightelf-options-button-highlight.blp',
    };
  }

  return {
    bg: '/buttons/esc/undead/undead-options-button-background.blp',
    bgDown: '/buttons/esc/undead/undead-options-button-background-down.blp',
    border: humanBorder,
    borderDown: humanBorderDown,
    hover: '/buttons/esc/undead/undead-options-button-highlight.blp',
  };
}

function sliderThumbCenterPercent(valuePct: number, trackPx: number, thumbPx: number): string {
  const clamped = Math.max(0, Math.min(100, valuePct));
  const min = thumbPx * 0.5;
  const max = Math.max(min, trackPx - thumbPx * 0.5);
  const center = min + ((max - min) * clamped) / 100;
  return `${(center / trackPx) * 100}%`;
}

function rotateCellClockwise(atlas: HTMLImageElement, cellIndex: number, cellW: number, cellH: number): HTMLCanvasElement {
  const canvas = document.createElement('canvas');
  canvas.width = cellH;
  canvas.height = cellW;
  const ctx = canvas.getContext('2d');
  if (!ctx) return canvas;
  ctx.translate(cellH, 0);
  ctx.rotate(Math.PI / 2);
  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
  return canvas;
}

function drawGlueNineSliceToCanvas(
  canvas: HTMLCanvasElement,
  bgImg: HTMLImageElement,
  borderImg: HTMLImageElement,
  hoverImg: HTMLImageElement | null,
  hovered: boolean,
) {
  const cssW = Math.max(1, canvas.clientWidth || 1);
  const cssH = Math.max(1, canvas.clientHeight || 1);
  const dpr = window.devicePixelRatio || 1;
  const pxW = Math.max(1, Math.round(cssW * dpr));
  const pxH = Math.max(1, Math.round(cssH * dpr));
  if (canvas.width !== pxW || canvas.height !== pxH) {
    canvas.width = pxW;
    canvas.height = pxH;
  }

  const ctx = canvas.getContext('2d');
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, cssW, cssH);

  const atlasW = borderImg.width;
  const atlasH = borderImg.height;
  const cellW = atlasW / 8;
  const corner = Math.max(1, Math.floor(Math.min(cellW, cssH * 0.35, cssW / 2, cssH / 2)));
  const inset = Math.max(1, Math.round(corner * 0.25));

  ctx.fillStyle = '#000';
  ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);

  const pattern = ctx.createPattern(bgImg, 'repeat');
  if (pattern) {
    ctx.fillStyle = pattern;
    ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
  }

  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
  };

  drawCell(4, 0, 0, corner, corner);
  drawCell(5, cssW - corner, 0, corner, corner);
  drawCell(6, 0, cssH - corner, corner, corner);
  drawCell(7, cssW - corner, cssH - corner, corner, corner);

  const edgeH = cssH - corner * 2;
  if (edgeH > 0) {
    drawCell(0, 0, corner, corner, edgeH);
    drawCell(1, cssW - corner, corner, corner, edgeH);
  }

  const edgeW = cssW - corner * 2;
  if (edgeW > 0) {
    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
    ctx.drawImage(topRot, corner, 0, edgeW, corner);
    ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
  }

  if (hovered && hoverImg) {
    const temp = document.createElement('canvas');
    temp.width = pxW;
    temp.height = pxH;
    const tCtx = temp.getContext('2d');
    if (tCtx) {
      tCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
      tCtx.drawImage(canvas, 0, 0, cssW, cssH);
      tCtx.globalCompositeOperation = 'source-in';
      tCtx.drawImage(hoverImg, 0, 0, cssW, cssH);
      ctx.save();
      ctx.globalCompositeOperation = 'lighter';
      ctx.drawImage(temp, 0, 0, cssW, cssH);
      ctx.restore();
    }
  }
}

interface FactionCardProps {
  race: Race;
  label: string;
  assets: Accessor<RacePreviewAssets>;
  sliderTrackBgUrl: Accessor<string>;
  sliderTrackBorderAtlasUrl: Accessor<string>;
  resizeTick: Accessor<number>;
}

function FactionPreviewCard(props: FactionCardProps) {
  let escButtonCanvasRef!: HTMLCanvasElement;
  let sliderCanvasRef!: HTMLCanvasElement;
  let sliderTrackRef!: HTMLDivElement;

  const [escButtonHovered, setEscButtonHovered] = createSignal(false);
  const [escButtonPressed, setEscButtonPressed] = createSignal(false);
  const [sliderValue, setSliderValue] = createSignal(55);

  const sliderKnobLeft = () => {
    props.resizeTick();
    const trackPx = Math.max(1, Math.round(sliderTrackRef?.clientWidth || escSliderTrackWidthPx));
    return sliderThumbCenterPercent(sliderValue(), trackPx, escSliderThumbWidthPx);
  };

  createEffect(() => {
    const canvas = escButtonCanvasRef;
    const bgUrl = escButtonPressed() ? props.assets().escBgDownUrl : props.assets().escBgUrl;
    const borderUrl = escButtonPressed() ? props.assets().escBorderDownUrl : props.assets().escBorderUrl;
    const hoverUrl = props.assets().escHoverUrl;
    const hoverActive = escButtonHovered() && !escButtonPressed();
    if (!canvas || !bgUrl || !borderUrl) return;
    let cancelled = false;

    void Promise.all([
      loadDataUrlImage(bgUrl),
      loadDataUrlImage(borderUrl),
      hoverUrl ? loadDataUrlImage(hoverUrl) : Promise.resolve(null),
    ])
      .then(([bgImg, borderImg, hoverImg]) => {
        if (cancelled) return;
        drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, hoverImg, hoverActive);
      })
      .catch((err) => console.error(err));

    onCleanup(() => {
      cancelled = true;
    });
  });

  createEffect(() => {
    props.resizeTick();
    const canvas = sliderCanvasRef;
    const bgUrl = props.sliderTrackBgUrl();
    const borderUrl = props.sliderTrackBorderAtlasUrl();
    if (!canvas || !bgUrl || !borderUrl) return;
    let cancelled = false;

    void Promise.all([loadDataUrlImage(bgUrl), loadDataUrlImage(borderUrl)])
      .then(([bgImg, borderImg]) => {
        if (cancelled) return;
        drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, null, false);
      })
      .catch((err) => console.error(err));

    onCleanup(() => {
      cancelled = true;
    });
  });

  return (
    <article class="faction-preview-card">
      <div class="faction-preview-label">{props.label}</div>
      <div class="faction-preview-samples">
        <div class="faction-preview-control">
          <div class="faction-preview-control-label">Button</div>
          <button
            type="button"
            class="esc-option-preview faction-preview-option-button"
            onMouseEnter={() => setEscButtonHovered(true)}
            onMouseLeave={() => {
              setEscButtonHovered(false);
              setEscButtonPressed(false);
            }}
            onMouseDown={() => setEscButtonPressed(true)}
            onMouseUp={() => setEscButtonPressed(false)}
          >
            <canvas ref={escButtonCanvasRef} class="esc-option-canvas" />
            <span
              class="esc-option-label"
              style={{
                transform: escButtonPressed()
                  ? `translate(${escButtonPressedOffsetXPx}px, ${escButtonPressedOffsetYPx}px)`
                  : 'none',
              }}
            >
              <span class="button-hotkey">O</span>ptions
            </span>
          </button>
        </div>

        <div class="faction-preview-control">
          <div class="faction-preview-control-label">Slider</div>
          <label class="esc-slider-demo faction-preview-slider-demo">
            <span class="esc-slider-value">{sliderValue()}%</span>
            <div ref={sliderTrackRef} class="esc-slider-track faction-preview-slider-track">
              <canvas ref={sliderCanvasRef} class="esc-slider-canvas" />
              <div
                class="esc-slider-knob"
                style={{
                  'background-image': props.assets().sliderKnobUrl ? `url("${props.assets().sliderKnobUrl}")` : 'none',
                  left: sliderKnobLeft(),
                }}
              />
              <input
                type="range"
                min="0"
                max="100"
                value={sliderValue()}
                aria-label={`${props.label} slider preview`}
                onInput={(event) => setSliderValue(Number(event.currentTarget.value))}
              />
            </div>
          </label>
        </div>

      </div>
    </article>
  );
}

export default function FactionPreviewSection() {
  const [raceAssets, setRaceAssets] = createSignal<Record<Race, RacePreviewAssets>>(EMPTY_RACE_PREVIEW_ASSET_MAP);
  const [sliderTrackBgUrl, setSliderTrackBgUrl] = createSignal('');
  const [sliderTrackBorderAtlasUrl, setSliderTrackBorderAtlasUrl] = createSignal('');
  const [resizeTick, setResizeTick] = createSignal(0);

  onMount(() => {
    let cancelled = false;

    void Promise.all([
      Promise.all(
        previewRaces.map(async ({ race }) => {
          const prefix = RACE_PREFIXES[race];
          const escSkin = getEscButtonSkin(race);
          const [escBgUrl, escBgDownUrl, escBorderUrl, escBorderDownUrl, escHoverUrl, sliderKnobUrl] = await Promise.all([
            loadBlpDataUrl(escSkin.bg),
            loadBlpDataUrl(escSkin.bgDown),
            loadBlpDataUrl(escSkin.border),
            loadBlpDataUrl(escSkin.borderDown),
            loadBlpDataUrl(escSkin.hover),
            loadBlpDataUrl(getEscSliderKnobPath(race)),
          ]);

          return [
            race,
            {
              escBgUrl,
              escBgDownUrl,
              escBorderUrl,
              escBorderDownUrl,
              escHoverUrl,
              sliderKnobUrl,
            } satisfies RacePreviewAssets,
          ] as const;
        }),
      ),
      loadBlpDataUrl('/buttons/slider/slider-background.blp'),
      loadBlpDataUrl('/buttons/slider/slider-border.blp'),
    ])
      .then(([entries, sliderBg, sliderBorder]) => {
        if (cancelled) return;
        const next: Record<Race, RacePreviewAssets> = {
          Human: { ...EMPTY_RACE_PREVIEW_ASSETS },
          Orc: { ...EMPTY_RACE_PREVIEW_ASSETS },
          NightElf: { ...EMPTY_RACE_PREVIEW_ASSETS },
          Undead: { ...EMPTY_RACE_PREVIEW_ASSETS },
        };
        for (const [race, assets] of entries) {
          next[race] = assets;
        }
        setRaceAssets(next);
        setSliderTrackBgUrl(sliderBg);
        setSliderTrackBorderAtlasUrl(sliderBorder);
      })
      .catch((err) => console.error(err));

    const onResize = () => setResizeTick((value) => value + 1);
    window.addEventListener('resize', onResize);

    onCleanup(() => {
      cancelled = true;
      window.removeEventListener('resize', onResize);
    });
  });

  return (
    <section class="section-card faction-preview-section">
      <p class="section-desc">
        Every component adapts to your chosen faction. One prop changes everything. We wish CSS had thought of this.
      </p>
      <div class="faction-preview">
        <For each={previewRaces}>
          {({ race, label }) => (
            <FactionPreviewCard
              race={race}
              label={label}
              assets={() => raceAssets()[race]}
              sliderTrackBgUrl={sliderTrackBgUrl}
              sliderTrackBorderAtlasUrl={sliderTrackBorderAtlasUrl}
              resizeTick={resizeTick}
            />
          )}
        </For>
      </div>
    </section>
  );
}

import { createSignal } from 'solid-js';
import type { Renderer } from '../../renderer/Renderer';
import Checkbox from '../Checkbox';
import RadioButton from '../RadioButton';
import Slider from '../Slider';
import EditBox from '../EditBox';

interface Props {
  renderer: Renderer;
}

export default function ControlsSection(props: Props) {
  const [selectedRadio, setSelectedRadio] = createSignal(0);

  return (
    <div class="tab-content">
      <div class="section-card">
        <h2>EscMenu Controls</h2>
        <p class="section-desc">Race-specific checkboxes, radio buttons, sliders, and edit boxes from the in-game Escape Menu.</p>
        <div class="menu-components-grid">
          <div class="menu-widget">
            <h3>Checkboxes</h3>
            <Checkbox label="Show Health Bars" initialChecked renderer={props.renderer} />
            <Checkbox label="Show Mana Bars" renderer={props.renderer} />
            <Checkbox label="Formation Toggle" initialChecked renderer={props.renderer} />
          </div>

          <div class="menu-widget">
            <h3>Radio Buttons</h3>
            <RadioButton label="Low" selected={() => selectedRadio() === 0} onSelect={() => setSelectedRadio(0)} renderer={props.renderer} />
            <RadioButton label="Medium" selected={() => selectedRadio() === 1} onSelect={() => setSelectedRadio(1)} renderer={props.renderer} />
            <RadioButton label="High" selected={() => selectedRadio() === 2} onSelect={() => setSelectedRadio(2)} renderer={props.renderer} />
          </div>

          <div class="menu-widget">
            <h3>Sliders</h3>
            <Slider label="Music Volume" initialValue={0.7} renderer={props.renderer} />
            <Slider label="SFX Volume" initialValue={0.85} renderer={props.renderer} />
            <Slider label="Mouse Speed" initialValue={0.5} renderer={props.renderer} />
          </div>

          <div class="menu-widget">
            <h3>Edit Boxes (Human)</h3>
            <EditBox text="Player Name" renderer={props.renderer} />
            <EditBox text="Azeroth-1" renderer={props.renderer} />
          </div>
        </div>
      </div>
    </div>
  );
}

import { For } from 'solid-js';
import type { Renderer } from '../../renderer/Renderer';
import GlueButton from '../GlueButton';
import MenuButton from '../MenuButton';
import OptionButton from '../OptionButton';
import { currentRace, RACE_PREFIXES } from '../../state/race';

interface Props {
  renderer: Renderer;
}

const GLUE_BG = 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBackground.png';
const GLUE_BORDER = 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBorder.png';
const GLUE_BG_DOWN = 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBackground-Down.png';
const GLUE_BORDER_DOWN = 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBorder-Down.png';
const GLUE_BORDERED = 'war3/Widgets/Glues/GlueScreen-Button1-BorderedBackdropBorder.png';
const GLUE_BORDERED_DOWN = 'war3/Widgets/Glues/GlueScreen-Button1-BorderedBackdropBorder-Down.png';
const GLUE_HOVER = 'war3/Widgets/BattleNet/bnet-button01-highlight-mouse.png';
const GLUE_BG_DISABLED = 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBackground-Disabled.png';
const GLUE_BORDER_DISABLED = 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBorder-Disabled.png';
const GLUE_FRAME = 'war3/Widgets/Glues/GlueScreen-Button1-Border.png';

export default function ButtonsSection(props: Props) {
  const rp = () => RACE_PREFIXES[currentRace()];
  const consoleBtnPath = () => {
    const race = currentRace();
    return `war3/Widgets/Console/${race}/${rp().lower}`;
  };
  const cmdBtnPath = () => `${consoleBtnPath()}-console-button`;

  return (
    <div class="tab-content">
      {/* Glue Screen Buttons */}
      <div class="section-card">
        <h2>Glue Screen Buttons (9-Slice Composited)</h2>
        <p class="section-desc">Main menu buttons use 9-slice compositing: a 32x32 tiled background + a 256x32 border atlas (8 pieces of 32x32: TL, T, TR, R, BR, B, BL, L). Shared across all races.</p>
        <div class="glue-buttons-grid">
          <div class="glue-btn-demo">
            <GlueButton bgPath={GLUE_BG} borderPath={GLUE_BORDER} bgDownPath={GLUE_BG_DOWN} borderDownPath={GLUE_BORDER_DOWN} hoverPath={GLUE_HOVER} renderer={props.renderer}>
              <div class="gb-label"><span class="hotkey">S</span>ingle Player</div>
            </GlueButton>
            <div class="glue-btn-state-label">Normal</div>
          </div>
          <div class="glue-btn-demo">
            <GlueButton bgPath={GLUE_BG} borderPath={GLUE_BORDERED} bgDownPath={GLUE_BG_DOWN} borderDownPath={GLUE_BORDERED_DOWN} hoverPath={GLUE_HOVER} renderer={props.renderer}>
              <div class="gb-label"><span class="hotkey">S</span>ingle Player</div>
            </GlueButton>
            <div class="glue-btn-state-label">Bordered</div>
          </div>
          <div class="glue-btn-demo">
