              <img src={`war3/Widgets/Console/${currentRace()}/CommandButton/${rp().lower}-activebutton.png`} style={{ width: '48px', height: '48px', border: '1px solid var(--card-border)', 'border-radius': '2px' }} />
              <div class="res-label">Active Button</div>
            </div>
            <div class="tooltip-res-card">
              <img src={`war3/Widgets/Console/${currentRace()}/CommandButton/${rp().lower}-multipleselection-border.png`} style={{ width: '48px', height: '48px', border: '1px solid var(--card-border)', 'border-radius': '2px' }} />
              <div class="res-label">Selection</div>
            </div>
            <div class="tooltip-res-card">
              <img src={`war3/Widgets/Console/${currentRace()}/CommandButton/${rp().lower}-multipleselection-heroglow.png`} style={{ width: '48px', height: '48px', border: '1px solid var(--card-border)', 'border-radius': '2px' }} />
              <div class="res-label">Hero Glow</div>
            </div>
            <div class="tooltip-res-card">
              <img src={`war3/Widgets/Console/${currentRace()}/CommandButton/${rp().lower}-subgroup-background.png`} style={{ width: '48px', height: '48px', border: '1px solid var(--card-border)', 'border-radius': '2px' }} />
              <div class="res-label">Subgroup BG</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function ConsoleButtonGroup(props: { title: string; items: { src: () => string; label: string }[] }) {
  return (
    <div class="console-btn-group">
      <h4>{props.title}</h4>
      <div class="console-btn-row">
        <For each={props.items}>{(item) =>
          <div class="console-btn-card">
            <img src={item.src()} alt={item.label} />
            <div class="cb-label">{item.label}</div>
          </div>
        }</For>
      </div>
    </div>
  );
}

