 27→const editBoxCornerRatio = 0.032 / 0.04;
 28→const editBoxInsetRatio = 0.004 / 0.04;
 29→const imageCache = new Map<string, Promise<HTMLImageElement>>();
 30→
 31→function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
 32→  const cached = imageCache.get(url);
 33→  if (cached) return cached;
 34→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
 35→    const img = new Image();
 36→    img.onload = () => resolve(img);
 37→    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
 38→    img.src = url;
 39→  });
 40→  imageCache.set(url, promise);
 41→  return promise;
 42→}
 43→
 44→function rotateCellClockwise(atlas: HTMLImageElement, cellIndex: number, cellW: number, cellH: number): HTMLCanvasElement {
 45→  const canvas = document.createElement('canvas');
 46→  canvas.width = cellH;
 47→  canvas.height = cellW;
 48→  const ctx = canvas.getContext('2d');
 49→  if (!ctx) return canvas;
 50→  ctx.translate(cellH, 0);
 51→  ctx.rotate(Math.PI / 2);
 52→  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
 53→  return canvas;
 54→}
 55→
 56→function drawHorizontallyTiledEdge(
 57→  ctx: CanvasRenderingContext2D,
 58→  tile: HTMLCanvasElement,
 59→  x: number,
 60→  y: number,
 61→  width: number,
 62→  height: number,
 63→) {
 64→  if (width <= 0 || height <= 0) return;
 65→
 66→  let drawn = 0;
 67→  while (drawn < width) {
 68→    const segmentW = Math.min(height, width - drawn);
 69→    const srcW = (segmentW / height) * tile.width;
 70→    ctx.drawImage(tile, 0, 0, srcW, tile.height, x + drawn, y, segmentW, height);
 71→    drawn += segmentW;
 72→  }
 73→}
 74→
 75→function fillRoundedRect(
 76→  ctx: CanvasRenderingContext2D,
 77→  x: number,
 78→  y: number,
 79→  width: number,
 80→  height: number,
 81→  radius: number,
 82→) {
 83→  const r = Math.max(0, Math.min(radius, width * 0.5, height * 0.5));
 84→  if (r <= 0) {
 85→    ctx.fillRect(x, y, width, height);
 86→    return;
 87→  }
 88→  ctx.beginPath();
 89→  ctx.moveTo(x + r, y);
 90→  ctx.lineTo(x + width - r, y);
 91→  ctx.quadraticCurveTo(x + width, y, x + width, y + r);
 92→  ctx.lineTo(x + width, y + height - r);
 93→  ctx.quadraticCurveTo(x + width, y + height, x + width - r, y + height);
 94→  ctx.lineTo(x + r, y + height);
 95→  ctx.quadraticCurveTo(x, y + height, x, y + height - r);
 96→  ctx.lineTo(x, y + r);
 97→  ctx.quadraticCurveTo(x, y, x + r, y);
 98→  ctx.closePath();
 99→  ctx.fill();
100→}
101→
102→function drawEditBoxFrame(canvas: HTMLCanvasElement, borderImg: HTMLImageElement, fillColor: string) {
103→  const cssW = Math.max(1, canvas.clientWidth || 1);
104→  const cssH = Math.max(1, canvas.clientHeight || 1);
105→  const dpr = window.devicePixelRatio || 1;
106→  const pxW = Math.max(1, Math.round(cssW * dpr));
107→  const pxH = Math.max(1, Math.round(cssH * dpr));
108→  if (canvas.width !== pxW || canvas.height !== pxH) {
109→    canvas.width = pxW;
110→    canvas.height = pxH;
111→  }
112→
113→  const ctx = canvas.getContext('2d');
114→  if (!ctx) return;
115→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
116→  ctx.clearRect(0, 0, cssW, cssH);
117→  ctx.imageSmoothingEnabled = true;
118→
119→  const atlasW = borderImg.width;
120→  const atlasH = borderImg.height;
121→  const cellW = atlasW / 8;
122→  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
123→  const corner = Math.max(1, Math.floor(Math.min(cssH * editBoxCornerRatio, sourceCornerMax, cssW / 2, cssH / 2)));
124→  const inset = Math.max(0, Math.floor(Math.min(cssH * editBoxInsetRatio, cssW / 2, cssH / 2)));
125→  const fillInset = inset + Math.max(1, Math.floor(cssH * 0.02));
126→  const innerX = fillInset;
127→  const innerY = fillInset;
128→  const innerW = Math.max(0, cssW - fillInset * 2);
129→  const innerH = Math.max(0, cssH - fillInset * 2);
130→  const innerRadius = Math.max(1, Math.floor(corner * 0.42));
131→
132→  if (innerW > 0 && innerH > 0) {
133→    ctx.save();
134→    ctx.globalAlpha = 0.88;
135→    ctx.fillStyle = fillColor;
136→    fillRoundedRect(ctx, innerX, innerY, innerW, innerH, innerRadius);
137→    ctx.restore();
138→  }
139→
140→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
141→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
142→  };
143→
144→  drawCell(4, 0, 0, corner, corner);
145→  drawCell(5, cssW - corner, 0, corner, corner);
146→  drawCell(6, 0, cssH - corner, corner, corner);
147→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
148→
149→  const edgeH = cssH - corner * 2;
150→  if (edgeH > 0) {
151→    drawCell(0, 0, corner, corner, edgeH);
152→    drawCell(1, cssW - corner, corner, corner, edgeH);
153→  }
