          <div class="tooltip-preview-head">
            <h4>Build Footman</h4>
            <span class="tooltip-hotkey">F</span>
          </div>
          <p>Basic frontline infantry. Strong against early pressure and pairs with priest support.</p>
          <div class="tooltip-costs">
            <span class="tooltip-cost"><img src={props.goldIconUrl} alt="" /> 135</span>
            <span class="tooltip-cost"><img src={props.lumberIconUrl} alt="" /> 0</span>
            <span class="tooltip-cost"><img src={props.supplyIconUrl} alt="" /> 2</span>
          </div>
        </article>
      </div>
    </section>
  );
}

export function PortraitFrameSection() {
  const race = () => currentRace();
  const racePrefix = () => RACE_PREFIXES[race()].tile;
  const portraitFrameSrc = () => `/console/${race()}/${racePrefix()}UIPortraitFrameCrop.png`;
  const portraitMaskSrc = () => `/console/${race()}/${racePrefix()}UIPortraitWindowMask.png`;

  return (
    <section class="section-card">
      <h3>PortraitFrame</h3>
      <p class="section-desc">
        A hero-tier avatar frame with live 3D portrait rendering. Because your users deserve better than a circle crop.
      </p>
      <div class="portrait-showcase">
        <div class="portrait-stage-wrap">
          <div class="portrait-stage">
            <div
              class="portrait-window"
              style={{
                '--portrait-window-mask': `url("${portraitMaskSrc()}")`,
              }}
            >
              <HeroPortraitModel race={race()} />
            </div>
            <img src={portraitFrameSrc()} alt="" class="portrait-frame-overlay" />
          </div>
        </div>
        <div class="button-state-label">3D Hero Portrait ({race()})</div>
      </div>
    </section>
  );
}

