        drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, null, false);
      })
      .catch((err) => console.error(err));

    return () => { cancelled = true; };
  }, [props.sliderTrackBgUrl, props.sliderTrackBorderAtlasUrl, props.resizeTick]);

  return (
