  1→import { createEffect, createSignal, onCleanup, onMount } from 'solid-js';
  2→import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
  3→import { mat4, quat, vec3 } from 'gl-matrix';
  4→import { RACE_PREFIXES } from '../state/race';
  5→import type { Race } from '../lib/types';
  6→
  7→type ModelType = ReturnType<typeof parseMDX>;
  8→
  9→const modelCache = new Map<Race, ModelType>();
 10→const blpCache = new Map<string, ImageData[]>();
 11→const widgetMaskCache = new Map<Race, string>();
 12→
 13→function computeVisibleBounds2D(model: ModelType): { minX: number; maxX: number; minY: number; maxY: number } | null {
 14→  let minX = Number.POSITIVE_INFINITY;
 15→  let maxX = Number.NEGATIVE_INFINITY;
 16→  let minY = Number.POSITIVE_INFINITY;
 17→  let maxY = Number.NEGATIVE_INFINITY;
 18→  let hasVisible = false;
 19→  for (const geoset of model.Geosets || []) {
 20→    if (!geoset.Faces || geoset.Faces.length === 0) continue;
 21→    const verts = geoset.Vertices;
 22→    for (let i = 0; i < verts.length; i += 3) {
 23→      const x = verts[i];
 24→      const y = verts[i + 1];
 25→      if (x < minX) minX = x;
 26→      if (x > maxX) maxX = x;
 27→      if (y < minY) minY = y;
 28→      if (y > maxY) maxY = y;
 29→      hasVisible = true;
 30→    }
 31→  }
 32→  if (!hasVisible) return null;
 33→  return { minX, maxX, minY, maxY };
 34→}
 35→
 36→function disableBackdropQuads(model: ModelType): void {
 37→  const hiddenNodes = new Set(['plane01', 'sunrise/set']);
 38→  for (const geoset of model.Geosets || []) {
 39→    const nodeIndex = geoset.Groups?.[0]?.[0];
 40→    if (nodeIndex == null) continue;
 41→    const nodeName = model.Nodes?.[nodeIndex]?.Name?.toLowerCase();
 42→    if (!nodeName || !hiddenNodes.has(nodeName)) continue;
 43→    geoset.Faces = new Uint16Array(0);
 44→  }
 45→}
 46→
 47→function getModelPath(race: Race): string {
 48→  const tile = RACE_PREFIXES[race].tile;
 49→  return `/models/time-indicator/${tile}UI-TimeIndicator.mdx`;
 50→}
 51→
 52→function getClockTexturePath(textureImage: string, race: Race): string | null {
 53→  const norm = textureImage.replaceAll('\\', '/').toLowerCase();
 54→  const tile = RACE_PREFIXES[race].tile;
 55→  const base = `/models/time-indicator/textures/${race}/`;
 56→
 57→  if (norm.includes('genericglowfaded')) return `${base}GenericGlowFaded.blp`;
 58→  if (norm.includes('star3')) return `${base}star3.blp`;
 59→  if (norm.includes('genericglow2_32')) return `${base}GenericGlow2_32.blp`;
 60→  if (norm.includes('timeindicatorframe')) return `${base}${tile}UITile-TimeIndicatorFrame.blp`;
 61→  if (norm.includes('timeindicator')) return `${base}HumanUITile-TimeIndicator.blp`;
 62→  return null;
 63→}
 64→
 65→function getFrameTexturePath(race: Race): string {
 66→  const tile = RACE_PREFIXES[race].tile;
 67→  return `/models/time-indicator/textures/${race}/${tile}UITile-TimeIndicatorFrame.blp`;
 68→}
 69→
 70→function findTransparentSeed(alpha: Uint8ClampedArray, width: number, height: number, startX: number, startY: number): number {
 71→  const inBounds = (x: number, y: number) => x >= 0 && y >= 0 && x < width && y < height;
 72→  const alphaAt = (x: number, y: number) => alpha[(y * width + x) * 4 + 3];
 73→  if (inBounds(startX, startY) && alphaAt(startX, startY) === 0) {
 74→    return startY * width + startX;
 75→  }
 76→  const maxRadius = Math.max(width, height);
 77→  for (let r = 1; r < maxRadius; r++) {
 78→    for (let dy = -r; dy <= r; dy++) {
 79→      const y = startY + dy;
 80→      const x1 = startX - r;
 81→      const x2 = startX + r;
 82→      if (inBounds(x1, y) && alphaAt(x1, y) === 0) return y * width + x1;
 83→      if (inBounds(x2, y) && alphaAt(x2, y) === 0) return y * width + x2;
 84→    }
 85→    for (let dx = -r + 1; dx <= r - 1; dx++) {
 86→      const x = startX + dx;
 87→      const y1 = startY - r;
 88→      const y2 = startY + r;
 89→      if (inBounds(x, y1) && alphaAt(x, y1) === 0) return y1 * width + x;
 90→      if (inBounds(x, y2) && alphaAt(x, y2) === 0) return y2 * width + x;
 91→    }
 92→  }
 93→  return -1;
 94→}
 95→
 96→async function loadWidgetMaskDataUrl(race: Race): Promise<string> {
 97→  const cached = widgetMaskCache.get(race);
 98→  if (cached) return cached;
 99→
100→  const frame = (await loadBLPMips(getFrameTexturePath(race)))[0];
101→  if (!frame || frame.width <= 0 || frame.height <= 0) {
102→    throw new Error(`Invalid frame texture for ${race}`);
103→  }
104→
105→  const width = frame.width;
106→  const height = frame.height;
107→  const seedX = Math.round(width * 0.49);
108→  const seedY = Math.round(height * 0.34);
109→  const seed = findTransparentSeed(frame.data, width, height, seedX, seedY);
110→  if (seed < 0) {
111→    throw new Error(`Unable to locate clock aperture for ${race}`);
112→  }
113→
114→  const aperture = new Uint8Array(width * height);
115→  const queue = new Int32Array(width * height);
116→  let head = 0;
117→  let tail = 0;
118→  queue[tail++] = seed;
119→  aperture[seed] = 1;
120→
121→  while (head < tail) {
122→    const cur = queue[head++];
123→    const x = cur % width;
124→    const y = (cur / width) | 0;
125→    const neighbors = [
126→      [x - 1, y],
127→      [x + 1, y],
128→      [x, y - 1],
129→      [x, y + 1],
130→    ];
131→    for (const [nx, ny] of neighbors) {
132→      if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
133→      const next = ny * width + nx;
134→      if (aperture[next]) continue;
135→      if (frame.data[next * 4 + 3] !== 0) continue;
136→      aperture[next] = 1;
137→      queue[tail++] = next;
138→    }
139→  }
140→
141→  const pixels = new Uint8ClampedArray(width * height * 4);
142→  for (let i = 0; i < width * height; i++) {
143→    const frameOpaque = frame.data[i * 4 + 3] > 0;
144→    const keep = frameOpaque || aperture[i] === 1;
145→    if (!keep) continue;
146→    const p = i * 4;
147→    pixels[p + 0] = 255;
148→    pixels[p + 1] = 255;
149→    pixels[p + 2] = 255;
150→    pixels[p + 3] = 255;
151→  }
152→
153→  const canvas = document.createElement('canvas');
154→  canvas.width = width;
155→  canvas.height = height;
156→  const ctx = canvas.getContext('2d');
157→  if (!ctx) throw new Error('Failed to create widget mask canvas');
158→  ctx.putImageData(new ImageData(pixels, width, height), 0, 0);
159→  const dataUrl = canvas.toDataURL('image/png');
160→  widgetMaskCache.set(race, dataUrl);
161→  return dataUrl;
162→}
163→
164→async function loadModel(race: Race): Promise<ModelType> {
165→  const cached = modelCache.get(race);
166→  if (cached) return cached;
167→  const res = await fetch(getModelPath(race));
168→  if (!res.ok) throw new Error(`Failed to fetch clock model for ${race}`);
169→  const ab = await res.arrayBuffer();
170→  const model = parseMDX(ab);
171→  disableBackdropQuads(model);
172→  modelCache.set(race, model);
173→  return model;
174→}
175→
176→async function loadBLPMips(path: string): Promise<ImageData[]> {
177→  const cached = blpCache.get(path);
178→  if (cached) return cached;
179→  const res = await fetch(path);
180→  if (!res.ok) throw new Error(`Failed to fetch texture ${path}`);
181→  const ab = await res.arrayBuffer();
182→  const blp = decodeBLP(ab);
183→  const mips: ImageData[] = [];
184→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
185→  for (let i = 0; i < maxLevels; i++) {
186→    const w = blp.width >> i;
187→    const h = blp.height >> i;
188→    if (w <= 0 || h <= 0) break;
189→    try {
190→      const img = getBLPImageData(blp, i);
191→      if (!img || !img.width || !img.height) break;
192→      mips.push(new ImageData(img.data, img.width, img.height));
193→      if (img.width === 1 && img.height === 1) break;
194→    } catch {
195→      // Some files expose invalid trailing mip entries; keep the valid levels we already decoded.
196→      break;
197→    }
198→  }
199→  if (mips.length === 0) {
200→    throw new Error(`No mip levels decoded for ${path}`);
201→  }
202→  blpCache.set(path, mips);
203→  return mips;
204→}
205→
206→interface TimeIndicatorModelProps {
207→  race: Race;
208→}
209→
210→export default function TimeIndicatorModel(props: TimeIndicatorModelProps) {
211→  let canvasRef!: HTMLCanvasElement;
212→  const [status, setStatus] = createSignal('init');
213→  const [widgetMaskUrl, setWidgetMaskUrl] = createSignal('');
214→  let gl: WebGLRenderingContext | WebGL2RenderingContext | null = null;
215→  let modelRenderer: ModelRenderer | null = null;
216→  let rafId = 0;
217→  let resizeObserver: ResizeObserver | null = null;
218→  let disposed = false;
219→  let initVersion = 0;
220→  let viewMinX = 0;
221→  let viewMaxX = 1;
222→  let viewMinY = 0;
223→  let viewMaxY = 1;
224→
225→  const mvMatrix = mat4.create();
226→  const pMatrix = mat4.create();
227→
228→  const destroyRenderer = () => {
229→    if (!modelRenderer) return;
230→    try {
231→      modelRenderer.destroy();
232→    } catch (err) {
233→      console.warn('clock renderer destroy failed', err);
234→    } finally {
235→      modelRenderer = null;
236→    }
237→  };
238→
239→  const resizeCanvas = () => {
240→    if (!canvasRef || !gl) return;
241→    const dpr = window.devicePixelRatio || 1;
242→    const w = Math.max(1, Math.round(canvasRef.clientWidth * dpr));
243→    const h = Math.max(1, Math.round(canvasRef.clientHeight * dpr));
244→    if (canvasRef.width !== w || canvasRef.height !== h) {
245→      canvasRef.width = w;
246→      canvasRef.height = h;
247→    }
248→    gl.viewport(0, 0, w, h);
249→  };
250→
251→  const startRenderLoop = () => {
252→    const startTs = performance.now();
253→    const tick = (now: number) => {
254→      if (disposed) return;
255→      rafId = requestAnimationFrame(tick);
256→      if (!gl) return;
257→      if (!modelRenderer) {
258→        setStatus('waiting renderer');
259→        return;
260→      }
261→
262→      resizeCanvas();
263→      const frame = ((now - startTs) * 1.0) % 60000;
264→      modelRenderer.setSequence(0);
265→      modelRenderer.setFrame(frame);
266→      modelRenderer.update(0);
267→
268→      mat4.identity(mvMatrix);
269→      const baseW = Math.max(1e-6, viewMaxX - viewMinX);
270→      const baseH = Math.max(1e-6, viewMaxY - viewMinY);
271→      const cx = (viewMinX + viewMaxX) * 0.5;
272→      const cy = (viewMinY + viewMaxY) * 0.5;
273→      const canvasAspect = Math.max(1e-6, canvasRef.clientWidth / Math.max(1, canvasRef.clientHeight));
274→      const modelAspect = baseW / baseH;
275→      let viewW = baseW * 1.04;
276→      let viewH = baseH * 1.04;
