331→      loadWidgetMaskDataUrl(race),
332→      Promise.all(texturePromises),
333→    ]);
334→    if (disposed || version !== initVersion) return;
335→    setWidgetMaskUrl(maskUrl);
336→    modelRenderer.setSequence(0);
337→    setStatus(`textures bound: ${race}`);
338→  };
339→
340→  onMount(() => {
341→    gl = canvasRef.getContext('webgl2', {
342→      alpha: true,
343→      premultipliedAlpha: false,
344→      antialias: true,
345→      depth: true,
346→      stencil: false,
347→    }) as WebGL2RenderingContext | null;
348→    if (!gl) {
349→      gl = canvasRef.getContext('webgl', {
350→        alpha: true,
351→        premultipliedAlpha: false,
352→        antialias: true,
353→        depth: true,
354→        stencil: false,
355→      });
356→    }
357→    if (!gl) {
358→      setStatus('no webgl context');
359→      return;
360→    }
361→
362→    setStatus('gl context ok');
363→    resizeCanvas();
364→    resizeObserver = new ResizeObserver(() => resizeCanvas());
365→    resizeObserver.observe(canvasRef);
366→    startRenderLoop();
367→    void initForRace(props.race);
368→  });
369→
370→  createEffect(() => {
371→    const race = props.race;
372→    if (!gl) return;
373→    void initForRace(race);
374→  });
375→
376→  onCleanup(() => {
377→    disposed = true;
378→    initVersion++;
379→    cancelAnimationFrame(rafId);
380→    resizeObserver?.disconnect();
381→    destroyRenderer();
382→  });
383→
384→  return (
385→    <>
386→      <canvas
387→        ref={canvasRef}
388→        style={{
389→          position: 'absolute',
390→          inset: '0',
391→          width: '100%',
392→          height: '100%',
393→          display: 'block',
394→          'pointer-events': 'none',
395→          'mask-image': widgetMaskUrl() ? `url("${widgetMaskUrl()}")` : 'none',
396→          '-webkit-mask-image': widgetMaskUrl() ? `url("${widgetMaskUrl()}")` : 'none',
397→          'mask-repeat': 'no-repeat',
398→          '-webkit-mask-repeat': 'no-repeat',
399→          'mask-size': '100% 100%',
400→          '-webkit-mask-size': '100% 100%',
401→          'mask-position': 'center',
402→          '-webkit-mask-position': 'center',
403→        }}
404→      />
405→    </>
406→  );
407→}
