      s.destroyed = true;
      window.removeEventListener('resize', onResize);
      if (s.resizeObserver) { s.resizeObserver.disconnect(); s.resizeObserver = null; }
      if (s.drawRaf) window.cancelAnimationFrame(s.drawRaf);
