        for (const texture of s.textureCache.values()) s.gl.deleteTexture(texture);
        if (s.quadBuffer) s.gl.deleteBuffer(s.quadBuffer);
        if (s.program) s.gl.deleteProgram(s.program);
      }
    };
  }, []);

