import { useState, useEffect, useRef } from 'react';
import type { Renderer } from '../renderer/Renderer';
import { useCurrentRace, setCurrentRace, RACE_PREFIXES } from '../state/race';
import { useGoldCurrent, useLumberCurrent } from '../state/resources';
import type { Race } from '../lib/types';
import TimeIndicatorModel from './TimeIndicatorModel';

interface Props {
  renderer: Renderer;
}

const RACES: Race[] = ['Human', 'Orc', 'NightElf', 'Undead'];

export default function TopHud(props: Props) {
  const race = useCurrentRace();

  return (
    <div className="top-hud">
      <div className="top-hud-tiles">
        <div className="top-hud-left">
          <div className="ths ths-1" />
          <div className="ths ths-2" />
        </div>
        <div className="top-hud-right">
          <div className="ths ths-3" />
          <div className="ths ths-4" />
          <div className="ths ths-5" />
        </div>
      </div>
      <div className="time-indicator">
        <TimeIndicatorModel race={race} />
      </div>
      <div className="top-hud-overlay">
        <div className="upper-buttons">
          {RACES.map((r) =>
            <UpperButton key={r} race={r} renderer={props.renderer} />
          )}
        </div>
        <div className="resources">
          <ResourceSlot type="gold" renderer={props.renderer} />
          <ResourceSlot type="lumber" renderer={props.renderer} />
          <ResourceSlot type="supply" renderer={props.renderer} />
          <span className="upkeep-text upkeep-green">No Upkeep</span>
        </div>
      </div>
    </div>
  );
}

function UpperButton(props: { race: Race; renderer: Renderer }) {
  const ref = useRef<HTMLButtonElement>(null);
  const [hovered, setHovered] = useState(false);
  const [pressed, setPressed] = useState(false);
  const currentRace = useCurrentRace();

  useEffect(() => {
    props.renderer.upperButtons.push({
      ref: () => ref.current!,
      race: props.race,
      hovered: () => hovered,
      pressed: () => pressed,
    });
  }, []);

  return (
    <button
      ref={ref}
      className={`upper-btn${currentRace === props.race ? ' active' : ''}`}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setHovered(false); setPressed(false); }}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      onClick={() => setCurrentRace(props.race)}
    >
      {RACE_PREFIXES[props.race].display}
    </button>
  );
}

function ResourceSlot(props: { type: 'gold' | 'lumber' | 'supply'; renderer: Renderer }) {
  const imgRef = useRef<HTMLImageElement>(null);
  const currentRace = useCurrentRace();
  const gold = useGoldCurrent();
  const lumber = useLumberCurrent();

  useEffect(() => {
    props.renderer.resourceIcons.push({
      ref: () => imgRef.current!,
      type: props.type,
    });
  }, []);

  const imgSrc = props.type === 'gold'
    ? 'war3/Feedback/Resources/ResourceGold.png'
    : props.type === 'lumber'
      ? 'war3/Feedback/Resources/ResourceLumber.png'
      : `war3/Feedback/Resources/Resource${currentRace}.png`;

  const value = props.type === 'gold' ? gold
    : props.type === 'lumber' ? lumber
    : '50 / 80';

  return (
    <div className="resource-slot">
      <img ref={imgRef} src={imgSrc} alt={props.type} />
      <span className="res-value">{value}</span>
    </div>
  );
}

