654→function drawTemplateNineSliceToCanvas(
655→  canvas: HTMLCanvasElement,
656→  bgImg: HTMLImageElement,
657→  borderImg: HTMLImageElement,
658→  options: NineSliceTemplateOptions,
659→) {
660→  const cssW = Math.max(1, canvas.clientWidth || 1);
661→  const cssH = Math.max(1, canvas.clientHeight || 1);
662→  const dpr = window.devicePixelRatio || 1;
663→  const pxW = Math.max(1, Math.round(cssW * dpr));
664→  const pxH = Math.max(1, Math.round(cssH * dpr));
665→  if (canvas.width !== pxW || canvas.height !== pxH) {
666→    canvas.width = pxW;
667→    canvas.height = pxH;
668→  }
669→
670→  const ctx = canvas.getContext('2d');
671→  if (!ctx) return;
672→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
673→  ctx.clearRect(0, 0, cssW, cssH);
674→
675→  const atlasW = borderImg.width;
676→  const atlasH = borderImg.height;
677→  const cellW = atlasW / 8;
678→  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
679→  const corner = Math.max(1, Math.floor(Math.min(options.cornerPx, sourceCornerMax, cssW / 2, cssH / 2)));
680→  const inset = Math.max(0, Math.floor(Math.min(options.insetPx, cssW / 2, cssH / 2)));
681→  const innerX = inset;
682→  const innerY = inset;
683→  const innerW = Math.max(0, cssW - inset * 2);
684→  const innerH = Math.max(0, cssH - inset * 2);
685→  // Large controls (textarea/listbox) reuse the same nine-slice templates; cap fill corner
686→  // radius to prevent over-rounded clipping that exposes page background.
687→  const fillCornerCapPx = options.fillCornerMaxPx ?? 8;
688→  const fillCorner = Math.max(0, Math.floor(Math.min(corner, fillCornerCapPx, innerW / 2, innerH / 2)));
689→
690→  if (innerW > 0 && innerH > 0) {
691→    ctx.save();
692→    ctx.beginPath();
693→    if (fillCorner > 0) {
694→      ctx.roundRect(innerX, innerY, innerW, innerH, fillCorner);
695→    } else {
696→      ctx.rect(innerX, innerY, innerW, innerH);
697→    }
698→    ctx.clip();
699→
700→    if (options.opaqueBaseFill) {
701→      ctx.fillStyle = options.opaqueBaseFill;
702→      ctx.fillRect(innerX, innerY, innerW, innerH);
703→    }
704→    if (options.tileBackground === false) {
705→      ctx.drawImage(bgImg, 0, 0, bgImg.width, bgImg.height, innerX, innerY, innerW, innerH);
706→    } else {
707→      const pattern = ctx.createPattern(bgImg, 'repeat');
708→      if (pattern) {
709→        ctx.fillStyle = pattern;
710→        ctx.fillRect(innerX, innerY, innerW, innerH);
711→      }
712→    }
713→    ctx.restore();
714→  }
715→
716→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
717→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
718→  };
719→
720→  drawCell(4, 0, 0, corner, corner);
721→  drawCell(5, cssW - corner, 0, corner, corner);
722→  drawCell(6, 0, cssH - corner, corner, corner);
723→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
724→
725→  const edgeH = cssH - corner * 2;
726→  if (edgeH > 0) {
727→    drawCell(0, 0, corner, corner, edgeH);
728→    drawCell(1, cssW - corner, corner, corner, edgeH);
729→  }
730→
731→  const edgeW = cssW - corner * 2;
732→  if (edgeW > 0) {
733→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
734→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
735→    if (options.tileHorizontalEdges) {
736→      drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
737→      drawHorizontallyTiledEdge(ctx, bottomRot, corner, cssH - corner, edgeW, corner);
738→    } else {
739→      ctx.drawImage(topRot, corner, 0, edgeW, corner);
740→      ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
741→    }
742→  }
743→}
