745→function composeBorderImageFromAtlas(atlas: HTMLImageElement): string {
746→  const cellW = atlas.width / 8;
747→  const cellH = atlas.height;
748→  const cell = Math.max(1, Math.floor(Math.min(cellW, cellH)));
749→  const canvas = document.createElement('canvas');
750→  canvas.width = cell * 3;
751→  canvas.height = cell * 3;
752→  const ctx = canvas.getContext('2d');
753→  if (!ctx) return '';
754→  ctx.clearRect(0, 0, canvas.width, canvas.height);
755→  ctx.imageSmoothingEnabled = false;
756→
757→  const drawCell = (idx: number, x: number, y: number) => {
758→    ctx.drawImage(atlas, idx * cellW, 0, cellW, cellH, x, y, cell, cell);
759→  };
760→
761→  drawCell(4, 0, 0);
762→  drawCell(5, cell * 2, 0);
763→  drawCell(6, 0, cell * 2);
764→  drawCell(7, cell * 2, cell * 2);
765→  drawCell(0, 0, cell);
766→  drawCell(1, cell * 2, cell);
767→
768→  const top = rotateCellClockwise(atlas, 2, cellW, cellH);
769→  const bottom = rotateCellClockwise(atlas, 3, cellW, cellH);
770→  ctx.drawImage(top, cell, 0, cell, cell);
771→  ctx.drawImage(bottom, cell, cell * 2, cell, cell);
772→
773→  return canvas.toDataURL('image/png');
774→}
