 881→function rgbHex([r, g, b]: [number, number, number]): string {
 882→  return `#${[r, g, b].map((c) => c.toString(16).padStart(2, '0')).join('')}`;
 883→}
 884→
 885→function healthBarTint(pct: number): string {
 886→  const p = Math.max(0, Math.min(100, pct));
 887→  const low: [number, number, number] = [220, 42, 22];
 888→  const mid: [number, number, number] = [238, 201, 46];
 889→  const high: [number, number, number] = [67, 213, 61];
 890→
 891→  if (p <= 35) return rgbHex(mixRgb(low, mid, p / 35));
 892→  return rgbHex(mixRgb(mid, high, (p - 35) / 65));
 893→}
 894→
 895→function easeOutCubic(t: number): number {
 896→  const clamped = Math.max(0, Math.min(1, t));
 897→  return 1 - (1 - clamped) ** 3;
 898→}
 899→
 900→function interpolateKeyframes(ms: number, keyframes: ReadonlyArray<readonly [number, number]>): number {
 901→  if (keyframes.length === 0) return 0;
 902→  if (ms <= keyframes[0][0]) return keyframes[0][1];
 903→  for (let i = 1; i < keyframes.length; i++) {
 904→    const [frameMs, frameVal] = keyframes[i];
 905→    const [prevMs, prevVal] = keyframes[i - 1];
 906→    if (ms <= frameMs) {
 907→      const t = (ms - prevMs) / Math.max(0.0001, frameMs - prevMs);
 908→      return prevVal + (frameVal - prevVal) * t;
 909→    }
 910→  }
 911→  return keyframes[keyframes.length - 1][1];
 912→}
 913→
 914→function loadingStutterPct(ms: number): number {
 915→  const stutterFrames = [
 916→    [0, 82.0],
 917→    [130, 82.8],
 918→    [230, 82.35],
 919→    [340, 83.95],
 920→    [430, 83.3],
 921→    [560, 85.2],
 922→    [650, 84.45],
 923→    [780, 87.25],
 924→    [870, 86.55],
 925→    [940, 88.9],
 926→    [1000, 90.0],
 927→  ] as const;
 928→  return interpolateKeyframes(ms, stutterFrames);
 929→}
 930→
 931→function loadingProgressPct(ms: number): number {
 932→  const cycleMs = progressAnimCycleMs;
 933→  const wrappedMs = ((ms % cycleMs) + cycleMs) % cycleMs;
 934→  const finalMs = cycleMs - loadingSmoothToStutterMs - loadingStutterDurationMs;
 935→
 936→  if (wrappedMs < loadingSmoothToStutterMs) {
 937→    const t = wrappedMs / loadingSmoothToStutterMs;
 938→    return easeOutCubic(t) * loadingStutterStartPct;
 939→  }
 940→
 941→  if (wrappedMs < loadingSmoothToStutterMs + loadingStutterDurationMs) {
 942→    return loadingStutterPct(wrappedMs - loadingSmoothToStutterMs);
 943→  }
 944→
 945→  const finalT = (wrappedMs - loadingSmoothToStutterMs - loadingStutterDurationMs) / Math.max(1, finalMs);
 946→  return loadingStutterEndPct + easeOutCubic(finalT) * (100 - loadingStutterEndPct);
 947→}
 948→
 949→function loadingGlowAlphaPct(pct: number): number {
 950→  const clampedPct = Math.max(0, Math.min(100, pct));
 951→  // LoadBar.mdx (Birth sequence) glow alpha keys:
 952→  // frame 3333:0, 13333:0, 26667:1, 26800:0.
 953→  const glowAlphaFrames = [
 954→    [0, 0],
 955→    [42.6135, 0],
 956→    [99.4332, 1],
 957→    [100, 0],
 958→  ] as const;
 959→  return interpolateKeyframes(clampedPct, glowAlphaFrames);
 960→}
