function shouldForceOpaqueOnZeroAlpha(path: string): boolean {
  return /\/buttons\/esc\/[^/]+\/[^/]+-options-button-background(?:-down|-disabled)?\.blp$/i.test(path);
}

function shouldApplyBlackColorKey(path: string): boolean {
  return /\/resources\/Resource(?:Lumber|Supply|Human|Orc|NightElf|Undead)\.blp$/i.test(path);
}

function sliderThumbCenterPercent(valuePct: number, trackPx: number, thumbPx: number): string {
  const clamped = Math.max(0, Math.min(100, valuePct));
  const min = thumbPx * 0.5;
  const max = Math.max(min, trackPx - thumbPx * 0.5);
  const center = min + ((max - min) * clamped) / 100;
  return `${(center / trackPx) * 100}%`;
}

function verticalThumbCenterPx(valuePct: number, trackTopPx: number, trackHeightPx: number, thumbPx: number): string {
  const clamped = Math.max(0, Math.min(100, valuePct));
  const min = trackTopPx + thumbPx * 0.5;
  const max = Math.max(min, trackTopPx + trackHeightPx - thumbPx * 0.5);
  const center = min + ((max - min) * clamped) / 100;
  return `${center}px`;
}

