                : 'translate(0, 0)';

            return (
              <button
                key={raceBtn}
                type="button"
                onMouseEnter={() => setHoveredRace(raceBtn)}
                onMouseLeave={() => {
                  setHoveredRace((prev: Race | null) => (prev === raceBtn ? null : prev));
                  setPressedRace((prev: Race | null) => (prev === raceBtn ? null : prev));
                }}
                onMouseDown={() => setPressedRace(raceBtn)}
                onMouseUp={() => setPressedRace((prev: Race | null) => (prev === raceBtn ? null : prev))}
                onClick={() => setCurrentRace(raceBtn)}
                style={{
                  position: 'relative',
                  width: compactTopHud ? `${100 / raceButtons.length}%` : `${upperButtonWidthVw}vw`,
                  height: '100%',
                  border: 'none',
                  padding: '0',
                  margin: '0',
                  background: 'transparent',
                  cursor: 'pointer',
                  pointerEvents: 'auto',
                }}
              >
                <div
                  style={{
                    position: 'absolute',
                    inset: '0',
                    backgroundImage: `url("${upperButtonAtlasUrl}")`,
                    backgroundRepeat: 'no-repeat',
                    backgroundSize: `${upperButtonBgSizeX}% ${upperButtonBgSizeY}%`,
                    backgroundPosition: `0 ${basePosY}`,
                  }}
                />
                <div
                  style={{
                    position: 'absolute',
                    inset: '0',
                    backgroundImage: `url("${upperButtonAtlasUrl}")`,
                    backgroundRepeat: 'no-repeat',
                    backgroundSize: `${upperButtonBgSizeX}% ${upperButtonBgSizeY}%`,
                    backgroundPosition: `0 ${upperButtonHighlightPosY}`,
                    opacity: showHighlight ? 1 : 0,
                    transition: 'opacity 80ms linear',
                    pointerEvents: 'none',
                    mixBlendMode: 'screen',
                  }}
                />
                <span
                  style={{
                    position: 'relative',
                    display: 'flex',
                    width: '100%',
                    height: '100%',
                    alignItems: 'center',
                    justifyContent: 'center',
                    color: textColor,
                    fontFamily: '"Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif',
                    fontSize: compactTopHud ? 'clamp(11px, 2.2vw, 14px)' : '1.25vw',
                    lineHeight: '1',
                    textShadow: '1px 1px 0 rgba(0, 0, 0, 0.95)',
                    transform: textTransform,
                    whiteSpace: 'nowrap',
                    userSelect: 'none',
                  }}
                >
                  {RACE_PREFIXES[raceBtn].display}
                </span>
              </button>
            );
          })}
        </div>

        {!compactTopHud && (
          <div
