 3→
 4→export const RACE_PREFIXES: Record<Race, RacePrefix> = {
 5→  Human:    { tile: 'Human',    esc: 'human',    lower: 'human',    display: 'Human' },
 6→  Orc:      { tile: 'Orc',      esc: 'orc',      lower: 'orc',      display: 'Orc' },
