 1→import { createExternalStore } from './createStore';
 2→
 3→const goldTargetStore = createExternalStore(500);
 4→const goldCurrentStore = createExternalStore(500);
 5→const lumberTargetStore = createExternalStore(300);
 6→const lumberCurrentStore = createExternalStore(300);
 7→
 8→function stepCounter(current: number, target: number): number {
 9→  if (current === target) return current;
10→  const diff = target - current;
11→  const next = current + Math.sign(diff) * Math.max(1, Math.floor(Math.abs(diff) * 0.2));
12→  return Math.abs(target - next) < 2 ? target : next;
13→}
14→
15→export function tickResources() {
16→  goldTargetStore.set(prev => Math.max(0, Math.min(9999, prev + Math.floor(Math.random() * 20) - 5)));
17→  lumberTargetStore.set(prev => Math.max(0, Math.min(9999, prev + Math.floor(Math.random() * 15) - 4)));
18→}
19→
20→export function animateCounters() {
21→  goldCurrentStore.set(prev => stepCounter(prev, goldTargetStore.get()));
22→  lumberCurrentStore.set(prev => stepCounter(prev, lumberTargetStore.get()));
23→}
24→
25→// Plain getters (non-reactive — use hooks in components)
26→export const goldCurrent = goldCurrentStore.get;
27→export const lumberCurrent = lumberCurrentStore.get;
28→export const goldTarget = goldTargetStore.get;
29→export const lumberTarget = lumberTargetStore.get;
30→
31→// Setters (work anywhere)
32→export const setGoldTarget = goldTargetStore.set;
33→export const setLumberTarget = lumberTargetStore.set;
34→
35→// Hooks (subscribe in React components)
36→export const useGoldCurrent = goldCurrentStore.useValue;
37→export const useLumberCurrent = lumberCurrentStore.useValue;
38→export const useGoldTarget = goldTargetStore.useValue;
39→export const useLumberTarget = lumberTargetStore.useValue;
40→
41→// Cheat codes
42→let cheatBuffer = '';
43→const CHEATS: Record<string, () => void> = {
44→  greedisgood: () => {
45→    goldTargetStore.set(prev => Math.min(9999, prev + 500));
46→    lumberTargetStore.set(prev => Math.min(9999, prev + 500));
47→  },
48→  keysersoze: () => { goldTargetStore.set(prev => Math.min(9999, prev + 500)); },
49→  leafittome: () => { lumberTargetStore.set(prev => Math.min(9999, prev + 500)); },
50→};
51→
52→export function handleCheatKey(key: string) {
53→  if (key.length === 1 && /[a-z]/i.test(key)) {
54→    cheatBuffer += key.toLowerCase();
55→    if (cheatBuffer.length > 20) cheatBuffer = cheatBuffer.slice(-20);
56→    for (const [code, fn] of Object.entries(CHEATS)) {
57→      if (cheatBuffer.endsWith(code)) {
58→        fn();
59→        cheatBuffer = '';
60→        break;
61→      }
62→    }
63→  }
64→}
