 3→/**
 4→ * Minimal external store compatible with React's useSyncExternalStore.
 5→ * Allows module-level state that can be read/written from anywhere
 6→ * and subscribed to from React components.
 7→ */
 8→export function createExternalStore<T>(initialValue: T) {
 9→  let value = initialValue;
10→  const listeners = new Set<() => void>();
11→
12→  function get(): T {
13→    return value;
14→  }
15→
16→  function set(next: T | ((prev: T) => T)): void {
17→    const nextValue = typeof next === 'function'
18→      ? (next as (prev: T) => T)(value)
19→      : next;
20→    if (!Object.is(nextValue, value)) {
21→      value = nextValue;
22→      listeners.forEach(l => l());
23→    }
24→  }
25→
26→  function subscribe(listener: () => void): () => void {
27→    listeners.add(listener);
28→    return () => { listeners.delete(listener); };
29→  }
30→
31→  /** Hook — subscribe a React component to this store's value. */
32→  function useValue(): T {
33→    return useSyncExternalStore(subscribe, get);
34→  }
35→
36→  return { get, set, useValue };
37→}
